import pandas as pdimport matplotlib.pyplot as pltfrom skopt import BayesSearchCVfrom skopt.space import Integer, Categoricalfrom sklearn.ensemble import RandomForestRegressorfrom joblib import dump# Certifique-se de que o arquivo tratamento_03.py está no mesmo diretóriofrom tratamento_03 import obter_dados_tratados_2ddef plotar_efeitos_principais(search_object):    """Gera gráficos mostrando a influência de cada hiperparâmetro no score médio."""    # 1. Converte os resultados da busca para um DataFrame    resultados = pd.DataFrame(search_object.cv_results_)        # 2. Filtra apenas as colunas de parâmetros e o score    colunas_param = [col for col in resultados.columns if col.startswith('param_')]        # 3. Cria a figura com subplots para cada hiperparâmetro    fig, axes = plt.subplots(1, len(colunas_param), figsize=(18, 5), sharey=True)    fig.suptitle('Análise de Efeitos Principais (Estilo Ensarioğlu et al.)', fontsize=16)        for i, col in enumerate(colunas_param):        # Agrupa pelo parâmetro e calcula a média do score        efeito = resultados.groupby(col)['mean_test_score'].mean()                nome_param = col.replace('param_', '')        axes[i].plot(efeito.index.astype(str), efeito.values, marker='o', linestyle='-', color='black')        axes[i].set_title(nome_param)        axes[i].set_xlabel('Valores')        axes[i].grid(True, linestyle='--', alpha=0.6)            axes[0].set_ylabel('Desempenho Médio (Score)')    plt.tight_layout(rect=[0, 0.03, 1, 0.95])    plt.show()def otimizar_random_forest():    print("--- Iniciando Otimização Bayesiana do Random Forest ---")        # Recebendo o dicionário com os DataFrames corretos    estagios = obter_dados_tratados_2d()    df_train = estagios['fs_train']        # Montando as matrizes de treino (Garantindo que 'FS' e 'DF' e 'RUL_CPD' existem no DataFrame)    X_train_2D = df_train[['FS', 'DF']].values    Y_train = df_train['RUL_CPD'].values        # 1. Definimos o espaço de busca usando os tipos do skopt    param_dist_bayes = {        'n_estimators': Integer(50, 500),                 'max_depth': Integer(10, 50),                     'min_samples_split': Integer(2, 10),              'min_samples_leaf': Integer(1, 4),                'max_features': Categorical(['sqrt', 'log2', 1.0])    }        rf_base = RandomForestRegressor(random_state=42)        # 2. Configurando o BayesSearchCV    bayes_search = BayesSearchCV(        estimator=rf_base,        search_spaces=param_dist_bayes,        n_iter=30,           # Número de iterações do processo Bayesiano        cv=3,                # Validação cruzada com 3 folds        verbose=2,        random_state=42,        n_jobs=-1            # Usa todos os núcleos do PC    )        print("Executando a busca Bayesiana... Isso pode levar alguns minutos.")    bayes_search.fit(X_train_2D, Y_train)        # CORREÇÃO: Usando a variável correta (bayes_search em vez de random_search)    plotar_efeitos_principais(bayes_search)        # 3. Extraindo os melhores resultados    melhor_modelo = bayes_search.best_estimator_    print("\nMelhores hiperparâmetros encontrados pela Otimização Bayesiana:")    print(bayes_search.best_params_)    print(f"Melhor Score (R2): {bayes_search.best_score_:.4f}")        # Salvar o modelo otimizado    dump(melhor_modelo, 'FD00x_rf.joblib')    print("Modelo salvo com sucesso como 'FD00x_rf.joblib'!")# Bloco principal de execuçãoif __name__ == "__main__":    otimizar_random_forest()        from sklearn.model_selection import RandomizedSearchCVfrom sklearn.ensemble import RandomForestRegressorfrom joblib import dumpfrom tratamento_03 import obter_dados_tratados_2ddef otimizar_random_forest():    print("--- Iniciando Otimização do Random Forest ---")    estagios = obter_dados_tratados_2d()    df_train = estagios['final']        X_train_2D = df_train[['FS', 'DF']].values    Y_train = df_train['RUL_CPD'].values    # Espaço de hiperparâmetros para a Busca Aleatória    param_dist = {        'n_estimators': [50, 100, 200, 300, 400, 500],        'max_depth': [None, 10, 20, 30, 40, 50],        'min_samples_split': [2, 5, 10],        'min_samples_leaf': [1, 2, 4],        'max_features': ['sqrt', 'log2', 1.0]     }    rf_base = RandomForestRegressor(random_state=42)        random_search = RandomizedSearchCV(        estimator=rf_base,        param_distributions=param_dist,        n_iter=30,           # Avalia 30 combinações aleatórias        cv=3,                # Validação cruzada com 3 folds        verbose=2,        random_state=42,        n_jobs=-1,           # Usa todos os núcleos        scoring='neg_mean_squared_error'    )        random_search.fit(X_train_2D, Y_train)        print("\nMelhores hiperparâmetros encontrados para o Random Forest:")    print(random_search.best_params_)        # Salva o melhor modelo    melhor_rf = random_search.best_estimator_    dump(melhor_rf, 'FD00x_rf.joblib')    print("Modelo Random Forest otimizado salvo com sucesso!")    return random_search.best_params_# Execução do scriptif __name__ == "__main__":    params_rf = otimizar_random_forest()